-- POSTGREsql is CASE SENSITIVE**** BE aWaRe!, btw MySQL is not.

select * from thomas;
-- Q1-total revenue generated by male vs female customer

select gender, sum(purchase_amount) as revenue from thomas
group by gender;
-- Q2- which customers used a discount coupon and still spent more than avg purchase amount?

select customer_id, purchase_amount from thomas
where discount_applied = 'Yes' and purchase_amount >= (select AVG(purchase_amount) from thomas);


-- NOTE- i can also write "where discount_applied ILIKE 'Yes' ", ILIKE removes case sensitvity from that query 

--Q3- top 5 products with highest avg review_rating?

select  item_purchased, avg(review_rating) from thomas 
group by item_purchased
order by avg (review_rating) desc
limit 5;


--OR


select  item_purchased, round(avg(review_rating)::numeric,2) from thomas 
group by item_purchased
order by avg (review_rating) desc
limit 5;



