-- Que- are customers who r repeat buyers(more than 5 previous purchases) also 
-- likely to subscribe
-- how to approach this ques- Among customers with previous_purchases > 5,
-- how many subscribed?
-- This is a relationship question.


select subscription_status,
count(customer_id) as repeat_buyers
from thomas
where previous_purchases > 5
group by subscription_status;  (#if want yes and no row section)



-- #above query answers -“How many repeat buyers subscribed?”


-- Q- revenue contribution of each age-group?
select age_group, sum(purchase_amount) as revenue
from thomas
group by age_group
order by revenue desc;



